class Solution:
    def soupServings(self, n):
        if n >= 4800:
            return 1.0
        units = (n + 24) // 25
        from functools import lru_cache
        @lru_cache(maxsize=None)
        def f(a, b):
            if a <= 0 and b <= 0:
                return 0.5
            if a <= 0:
                return 1.0
            if b <= 0:
                return 0.0
            return 0.25 * (f(a - 4, b) + f(a - 3, b - 1) + f(a - 2, b - 2) + f(a - 1, b - 3))
        return f(units, units)

